using MudBlazor.UnitTests.Shared.Extensions;

static void AssertBreadcrumbNavLabel(IRenderedComponent<MudBreadcrumbs> component, string scenario)
{
    var nav = component.Find("nav");
    var ariaLabel = nav.GetAttribute("aria-label");
    if (ariaLabel != "Breadcrumb")
    {
        Console.Error.WriteLine($"FAIL ({scenario}): expected nav aria-label=\"Breadcrumb\", actual={(ariaLabel is null ? "<null>" : $"\"{ariaLabel}\"")}");
        Console.WriteLine(component.Markup);
        Environment.Exit(1);
