using var context = new BunitContext();
context.AddTestServices();

var normalItems = new List<BreadcrumbItem>
{
    new("Home", "/"),
    new("Library", "/library"),
    new("Current", null, disabled: true)
};
var normal = context.Render<MudBreadcrumbs>(parameters => parameters.Add(x => x.Items, normalItems));
AssertBreadcrumbNavLabel(normal, "normal items");

var collapsedItems = new List<BreadcrumbItem>
{
    new("One", "/one"),
    new("Two", "/two"),
    new("Three", "/three"),
    new("Four", "/four"),
    new("Five", null, disabled: true)
};
